created = 0
errors = 0

stories.each do |attrs|
  s = Story.new(attrs)
  s.is_active = true

  if s.save(validate: false)
    # Géocodage
    if s.location.present? && s.latitude.blank?
      s.geocode
      s.save(validate: false) if s.latitude.present?
    end
    puts "OK #{s.id} | #{s.title[0..60]}"
    created += 1
  else
    puts "ERR | #{s.title[0..60]} | #{s.errors.full_messages.join(', ')}"
    errors += 1
  end
end

puts "---"
puts "#{created} stories créées, #{errors} erreurs."
